        {
            InitializeComponent();
            Hide();
            ShowInTaskbar = false;
            Notification_Informer.BalloonTipTitle = " The App is in System tray";
            Notification_Informer.BalloonTipText = "To disable the app from starting, uncheck Start with Windows checkbox";
